import assert from 'node:assert/strict';
import test from 'node:test';

process.env.API_FOOTBALL_KEY ??= 'test-server-key';

const { filterInjuriesForMatch } = await import('../../src/routes/matches/absences.ts');

function playerName(entry: unknown): unknown {
  if (!entry || typeof entry !== 'object') {
    return null;
  }
  const record = entry as Record<string, unknown>;
  const player = record.player;
  if (!player || typeof player !== 'object') {
    return null;
  }
  return (player as Record<string, unknown>).name ?? null;
}

test('filterInjuriesForMatch returns empty when no injuries are provided', () => {
  assert.deepEqual(filterInjuriesForMatch([], 202, Date.parse('2026-02-21T20:00:00Z')), []);
});

test('filterInjuriesForMatch prefers exact fixture id and sorts by date then player name', () => {
  const response = filterInjuriesForMatch(
    [
      null,
      { fixture: { id: 202, date: '2026-02-21T20:00:00Z' }, player: { name: 123 } },
      { fixture: { id: 202, date: '2026-02-21T20:00:00Z' }, player: { name: 'Charlie' } },
      { fixture: { id: 202, date: '2026-02-21T20:00:00Z' }, player: 'invalid-player-shape' },
      { fixture: { id: 202, date: '2026-02-20T20:00:00Z' }, player: { name: 'Bravo' } },
      { fixture: { id: 202 }, player: { name: 'Alpha' } },
      { fixture: { id: 201, date: '2026-02-21T20:00:00Z' }, player: { name: 'Ignored' } },
    ],
    202,
    Date.parse('2026-02-21T20:00:00Z'),
  );

  assert.equal(response.length, 5);
  assert.deepEqual(response.map(playerName), [123, null, 'Charlie', 'Bravo', 'Alpha']);
});

test('filterInjuriesForMatch falls back to nearby dates when exact fixture entries are missing', () => {
  const matchDateMs = Date.parse('2026-02-21T20:00:00Z');
  const response = filterInjuriesForMatch(
    [
      { fixture: { id: 999, timestamp: Math.floor(matchDateMs / 1_000) }, player: { name: 'Same day' } },
      { fixture: { id: 998, date: '2026-02-22T20:00:00Z' }, player: { name: 'One day after' } },
      { fixture: { id: 997, date: '2026-02-24T20:00:00Z' }, player: { name: 'Too far' } },
      { fixture: { id: 996 }, player: { name: 'No date metadata' } },
      { fixture: null, player: { name: 'Invalid fixture payload' } },
      'invalid-entry-shape',
    ],
    202,
    matchDateMs,
  );

  assert.equal(response.length, 2);
  assert.deepEqual(response.map(playerName), ['One day after', 'Same day']);
});

test('filterInjuriesForMatch returns empty when match date is unknown and no exact fixture exists', () => {
  const response = filterInjuriesForMatch(
    [{ fixture: { id: 999, date: '2026-02-21T20:00:00Z' }, player: { name: 'Ignored' } }],
    202,
    null,
  );
  assert.deepEqual(response, []);
});

test('filterInjuriesForMatch keeps dated injuries ahead of entries without date metadata', () => {
  const fixtureId = 202;
  const payloadA = filterInjuriesForMatch(
    [
      { fixture: { id: fixtureId, date: '2026-02-21T20:00:00Z' }, player: { name: 'Dated' } },
      { fixture: { id: fixtureId }, player: { name: 'NoDate' } },
    ],
    fixtureId,
    Date.parse('2026-02-21T20:00:00Z'),
  );

  const payloadB = filterInjuriesForMatch(
    [
      { fixture: { id: fixtureId }, player: { name: 'NoDate' } },
      { fixture: { id: fixtureId, date: '2026-02-21T20:00:00Z' }, player: { name: 'Dated' } },
    ],
    fixtureId,
    Date.parse('2026-02-21T20:00:00Z'),
  );

  assert.deepEqual(payloadA.map(playerName), ['Dated', 'NoDate']);
  assert.deepEqual(payloadB.map(playerName), ['Dated', 'NoDate']);
});

import { toDateMilliseconds, toEpochMilliseconds, toNumericId } from './fixtureContext.js';

function toInjuryFixtureId(value: unknown): number | null {
  if (!value || typeof value !== 'object') {
    return null;
  }

  const record = value as Record<string, unknown>;
  const fixture = record.fixture;
  if (!fixture || typeof fixture !== 'object') {
    return null;
  }

  const fixtureRecord = fixture as Record<string, unknown>;
  return toNumericId(fixtureRecord.id);
}

function toInjuryFixtureDateMs(value: unknown): number | null {
  if (!value || typeof value !== 'object') {
    return null;
  }

  const record = value as Record<string, unknown>;
  const fixture = record.fixture;
  if (!fixture || typeof fixture !== 'object') {
    return null;
  }

  const fixtureRecord = fixture as Record<string, unknown>;
  return toEpochMilliseconds(fixtureRecord.timestamp) ?? toDateMilliseconds(fixtureRecord.date);
}

function toInjuryPlayerName(value: unknown): string {
  if (!value || typeof value !== 'object') {
    return '';
  }

  const record = value as Record<string, unknown>;
  const player = record.player;
  if (!player || typeof player !== 'object') {
    return '';
  }

  const playerRecord = player as Record<string, unknown>;
  if (typeof playerRecord.name !== 'string') {
    return '';
  }

  return playerRecord.name.trim().toLowerCase();
}

function sortInjuriesByDate(entries: unknown[]): unknown[] {
  return [...entries].sort((left, right) => {
    const leftDate = toInjuryFixtureDateMs(left);
    const rightDate = toInjuryFixtureDateMs(right);

    if (leftDate === null && rightDate !== null) {
      return 1;
    }

    if (leftDate !== null && rightDate === null) {
      return -1;
    }

    if (leftDate !== null && rightDate !== null && leftDate !== rightDate) {
      return rightDate - leftDate;
    }

    return toInjuryPlayerName(left).localeCompare(toInjuryPlayerName(right));
  });
}

export function filterInjuriesForMatch(
  entries: unknown[],
  matchFixtureId: number,
  matchFixtureDateMs: number | null,
): unknown[] {
  if (entries.length === 0) {
    return [];
  }

  const exactFixtureEntries = entries.filter(entry => toInjuryFixtureId(entry) === matchFixtureId);
  if (exactFixtureEntries.length > 0) {
    return sortInjuriesByDate(exactFixtureEntries);
  }

  if (matchFixtureDateMs === null) {
    return [];
  }

  const oneDayMs = 24 * 60 * 60 * 1_000;
  const nearbyEntries = entries.filter(entry => {
    const injuryDateMs = toInjuryFixtureDateMs(entry);
    if (injuryDateMs === null) {
      return false;
    }

    return Math.abs(injuryDateMs - matchFixtureDateMs) <= oneDayMs;
  });

  return sortInjuriesByDate(nearbyEntries);
}

import { apiFootballGet } from '../../lib/apiFootballClient.js';
import { withCache } from '../../lib/cache.js';

export type FixtureContext = {
  fixture?: {
    id?: number;
    date?: string;
    timestamp?: number;
  };
  league?: {
    id?: number;
    season?: number;
  };
  teams?: {
    home?: {
      id?: number;
    };
    away?: {
      id?: number;
    };
  };
};

type FixtureListResponse = {
  response?: FixtureContext[];
};

export function toNumericId(value: unknown): number | null {
  return typeof value === 'number' && Number.isFinite(value) ? value : null;
}

export function toEpochMilliseconds(value: unknown): number | null {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return null;
  }

  if (value > 1_000_000_000_000) {
    return value;
  }

  if (value > 1_000_000_000) {
    return value * 1_000;
  }

  return null;
}

export function toDateMilliseconds(value: unknown): number | null {
  if (typeof value !== 'string') {
    return null;
  }

  const timestamp = Date.parse(value);
  return Number.isFinite(timestamp) ? timestamp : null;
}

function buildFixtureContextKey(matchId: string, timezone?: string): string {
  return timezone ? `match:context:${matchId}:${timezone}` : `match:context:${matchId}`;
}

export async function fetchFixtureContext(matchId: string, timezone?: string): Promise<FixtureContext | null> {
  const contextKey = buildFixtureContextKey(matchId, timezone);
  const payload = await withCache(contextKey, 30_000, () =>
    apiFootballGet<FixtureListResponse>(
      timezone
        ? `/fixtures?id=${encodeURIComponent(matchId)}&timezone=${encodeURIComponent(timezone)}`
        : `/fixtures?id=${encodeURIComponent(matchId)}`,
    ),
  );

  return payload.response?.[0] ?? null;
}

import { env } from '../config/env.js';
import { UpstreamBffError } from './errors.js';

const RETRIABLE_STATUS_CODES = new Set([429, 500, 502, 503, 504]);

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function buildTimeoutSignal(timeoutMs: number, parentSignal?: AbortSignal): AbortSignal {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  parentSignal?.addEventListener('abort', () => controller.abort(), {
    once: true,
  });

  controller.signal.addEventListener(
    'abort',
    () => {
      clearTimeout(timeoutId);
    },
    { once: true },
  );

  return controller.signal;
}

function normalizeBody(body: string): string {
  return body.slice(0, 1_000);
}

function isAbortError(error: unknown): boolean {
  return error instanceof Error && error.name === 'AbortError';
}

function shouldRetryStatus(status: number): boolean {
  return RETRIABLE_STATUS_CODES.has(status);
}

function buildUrl(pathWithQuery: string): string {
  return `${env.apiFootballBaseUrl}${pathWithQuery}`;
}

export async function apiFootballGet<T>(
  pathWithQuery: string,
  signal?: AbortSignal,
): Promise<T> {
  let lastError: unknown = null;

  for (let attempt = 0; attempt <= env.apiMaxRetries; attempt += 1) {
    const requestSignal = buildTimeoutSignal(env.apiTimeoutMs, signal);

    try {
      const response = await fetch(buildUrl(pathWithQuery), {
        method: 'GET',
        headers: {
          Accept: 'application/json',
          'x-apisports-key': env.apiFootballKey,
        },
        signal: requestSignal,
      });

      if (!response.ok) {
        const responseBody = normalizeBody(await response.text());
        if (attempt < env.apiMaxRetries && shouldRetryStatus(response.status)) {
          await sleep(150 * (attempt + 1));
          continue;
        }

        throw new UpstreamBffError(
          response.status,
          'UPSTREAM_HTTP_ERROR',
          `API-Football returned HTTP ${response.status}.`,
          responseBody,
        );
      }

      return (await response.json()) as T;
    } catch (error) {
      if (error instanceof UpstreamBffError) {
        throw error;
      }

      lastError = error;
      const canRetry = attempt < env.apiMaxRetries;

      if (canRetry && (isAbortError(error) || error instanceof TypeError)) {
        await sleep(150 * (attempt + 1));
        continue;
      }

      throw new UpstreamBffError(
        502,
        'UPSTREAM_UNAVAILABLE',
        'Unable to reach API-Football from BFF.',
        error instanceof Error ? error.message : String(error),
      );
    }
  }

  throw new UpstreamBffError(
    502,
    'UPSTREAM_UNAVAILABLE',
    'Unable to reach API-Football from BFF.',
    lastError,
  );
}

const DEFAULT_PORT = 3001;
const DEFAULT_HOST = '0.0.0.0';
const DEFAULT_API_BASE_URL = 'https://v3.football.api-sports.io';
const DEFAULT_API_TIMEOUT_MS = 10_000;
const DEFAULT_API_MAX_RETRIES = 2;
const DEFAULT_RATE_LIMIT_MAX = 120;
const DEFAULT_RATE_LIMIT_WINDOW_MS = 60_000;
const DEFAULT_TRUST_PROXY_HOPS = 0;
const DEFAULT_CACHE_MAX_ENTRIES = 1_000;
const DEFAULT_CACHE_CLEANUP_INTERVAL_MS = 60_000;
const DEFAULT_CACHE_BACKEND = 'memory';
const DEFAULT_REDIS_CACHE_PREFIX = 'footalert:bff:';
const DEFAULT_BFF_EXPOSE_ERROR_DETAILS = false;
const DEFAULT_MOBILE_REQUEST_SIGNATURE_MAX_SKEW_MS = 5 * 60_000;

type CacheBackend = 'memory' | 'redis';

type BffEnv = {
  port: number;
  host: string;
  apiFootballBaseUrl: string;
  apiFootballKey: string;
  apiTimeoutMs: number;
  apiMaxRetries: number;
  rateLimitMax: number;
  rateLimitWindowMs: number;
  trustProxyHops: number;
  corsAllowedOrigins: string[];
  webAppOrigin: string | null;
  cacheMaxEntries: number;
  cacheCleanupIntervalMs: number;
  cacheBackend: CacheBackend;
  redisUrl: string | null;
  redisCachePrefix: string;
  bffExposeErrorDetails: boolean;
  mobileRequestSigningKey: string | null;
  mobileRequestSignatureMaxSkewMs: number;
};

function normalizeUrl(value: string): string {
  return value.replace(/\/+$/, '');
}

function readPositiveInt(rawValue: string | undefined, fallback: number): number {
  if (!rawValue) {
    return fallback;
  }

  const parsed = Number.parseInt(rawValue, 10);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    return fallback;
  }

  return parsed;
}

function readApiFootballKey(): string {
  const apiFootballKey = process.env.API_FOOTBALL_KEY?.trim();
  if (!apiFootballKey) {
    throw new Error('Missing API_FOOTBALL_KEY in BFF environment.');
  }

  return apiFootballKey;
}

function readOptionalSigningKey(rawValue: string | undefined): string | null {
  const signingKey = rawValue?.trim();
  return signingKey ? signingKey : null;
}

function readBoolean(rawValue: string | undefined, fallback: boolean): boolean {
  if (!rawValue) {
    return fallback;
  }

  const normalized = rawValue.trim().toLowerCase();
  if (normalized === '1' || normalized === 'true' || normalized === 'yes') {
    return true;
  }

  if (normalized === '0' || normalized === 'false' || normalized === 'no') {
    return false;
  }

  return fallback;
}

function readCacheBackend(rawValue: string | undefined): CacheBackend {
  const normalized = rawValue?.trim().toLowerCase();
  if (normalized === 'redis') {
    return 'redis';
  }

  return 'memory';
}

function readOptionalValue(rawValue: string | undefined): string | null {
  const value = rawValue?.trim();
  return value ? value : null;
}

function readRedisCachePrefix(rawValue: string | undefined): string {
  const prefix = rawValue?.trim();
  if (!prefix) {
    return DEFAULT_REDIS_CACHE_PREFIX;
  }

  return prefix;
}

function readCsvList(rawValue: string | undefined): string[] {
  if (!rawValue) {
    return [];
  }

  return rawValue
    .split(',')
    .map(value => value.trim())
    .filter(Boolean);
}

function readOptionalOrigin(rawValue: string | undefined): string | null {
  const trimmed = rawValue?.trim();
  if (!trimmed) {
    return null;
  }

  try {
    const parsed = new URL(trimmed);
    return parsed.origin;
  } catch {
    throw new Error(`Invalid WEB_APP_ORIGIN value: "${trimmed}"`);
  }
}

function buildCorsAllowedOrigins(rawOrigins: string | undefined, webAppOrigin: string | null): string[] {
  const normalizedOrigins = new Set<string>(readCsvList(rawOrigins));
  if (webAppOrigin) {
    normalizedOrigins.add(webAppOrigin);
  }

  return [...normalizedOrigins];
}

function isProxyLikeEnvironment(trustProxyHops: number): boolean {
  const runtimeEnv = process.env.APP_ENV?.trim().toLowerCase() || process.env.NODE_ENV?.trim().toLowerCase();
  if (runtimeEnv === 'production' || runtimeEnv === 'staging') {
    return true;
  }

  return trustProxyHops > 0;
}

export const env: BffEnv = {
  port: readPositiveInt(process.env.PORT, DEFAULT_PORT),
  host: process.env.HOST?.trim() || DEFAULT_HOST,
  apiFootballBaseUrl: normalizeUrl(
    process.env.API_FOOTBALL_BASE_URL?.trim() || DEFAULT_API_BASE_URL,
  ),
  apiFootballKey: readApiFootballKey(),
  apiTimeoutMs: readPositiveInt(process.env.API_TIMEOUT_MS, DEFAULT_API_TIMEOUT_MS),
  apiMaxRetries: readPositiveInt(process.env.API_MAX_RETRIES, DEFAULT_API_MAX_RETRIES),
  rateLimitMax: readPositiveInt(process.env.RATE_LIMIT_MAX, DEFAULT_RATE_LIMIT_MAX),
  rateLimitWindowMs: readPositiveInt(
    process.env.RATE_LIMIT_WINDOW_MS,
    DEFAULT_RATE_LIMIT_WINDOW_MS,
  ),
  trustProxyHops: readPositiveInt(process.env.TRUST_PROXY_HOPS, DEFAULT_TRUST_PROXY_HOPS),
  webAppOrigin: readOptionalOrigin(process.env.WEB_APP_ORIGIN),
  corsAllowedOrigins: [],
  cacheMaxEntries: readPositiveInt(
    process.env.CACHE_MAX_ENTRIES,
    DEFAULT_CACHE_MAX_ENTRIES,
  ),
  cacheCleanupIntervalMs: readPositiveInt(
    process.env.CACHE_CLEANUP_INTERVAL_MS,
    DEFAULT_CACHE_CLEANUP_INTERVAL_MS,
  ),
  cacheBackend: readCacheBackend(process.env.CACHE_BACKEND || DEFAULT_CACHE_BACKEND),
  redisUrl: readOptionalValue(process.env.REDIS_URL),
  redisCachePrefix: readRedisCachePrefix(process.env.REDIS_CACHE_PREFIX),
  bffExposeErrorDetails: readBoolean(
    process.env.BFF_EXPOSE_ERROR_DETAILS,
    DEFAULT_BFF_EXPOSE_ERROR_DETAILS,
  ),
  mobileRequestSigningKey: readOptionalSigningKey(process.env.MOBILE_REQUEST_SIGNING_KEY),
  mobileRequestSignatureMaxSkewMs: readPositiveInt(
    process.env.MOBILE_REQUEST_SIGNATURE_MAX_SKEW_MS,
    DEFAULT_MOBILE_REQUEST_SIGNATURE_MAX_SKEW_MS,
  ),
};

env.corsAllowedOrigins = buildCorsAllowedOrigins(process.env.CORS_ALLOWED_ORIGINS, env.webAppOrigin);

env.trustProxyHops = Math.max(env.trustProxyHops, 0);

if (isProxyLikeEnvironment(env.trustProxyHops) && env.corsAllowedOrigins.length === 0) {
  throw new Error(
    'Missing CORS_ALLOWED_ORIGINS in proxy/staging/production mode.',
  );
}

export class BffError extends Error {
  constructor(
    public readonly statusCode: number,
    public readonly code: string,
    message: string,
    public readonly details?: unknown,
  ) {
    super(message);
  }
}

export class ValidationBffError extends BffError {
  constructor(details: unknown) {
    super(400, 'VALIDATION_ERROR', 'Invalid request parameters.', details);
  }
}

export class UpstreamBffError extends BffError {
  constructor(
    statusCode: number,
    code: string,
    message: string,
    details?: unknown,
  ) {
    super(statusCode, code, message, details);
  }
}

import { createHash } from 'node:crypto';
import { Redis as IORedis } from 'ioredis';

type CacheEntry<T> = {
  expiresAt: number;
  value: T;
};

type CacheBackend = 'memory' | 'redis';

type CacheConfig = {
  maxEntries: number;
  cleanupIntervalMs: number;
  backend: CacheBackend;
  redisUrl: string | null;
  redisPrefix: string;
};

const DEFAULT_CACHE_MAX_ENTRIES = 1_000;
const DEFAULT_CACHE_CLEANUP_INTERVAL_MS = 60_000;
const DEFAULT_MAX_CACHE_KEY_LENGTH = 120;
const DEFAULT_CACHE_BACKEND: CacheBackend = 'memory';
const DEFAULT_REDIS_PREFIX = 'footalert:bff:';

function toPositiveInt(value: number, fallback: number): number {
  if (!Number.isFinite(value) || value <= 0) {
    return fallback;
  }

  return Math.floor(value);
}

function normalizeBackend(rawValue: string | undefined): CacheBackend {
  return rawValue === 'redis' ? 'redis' : 'memory';
}

function normalizeRedisPrefix(rawValue: string | undefined): string {
  const normalized = rawValue?.trim();
  if (!normalized) {
    return DEFAULT_REDIS_PREFIX;
  }

  return normalized;
}

function hashCacheKey(rawKey: string): string {
  if (rawKey.length <= DEFAULT_MAX_CACHE_KEY_LENGTH) {
    return rawKey;
  }

  return `sha256:${createHash('sha256').update(rawKey).digest('hex')}`;
}

export class MemoryCache {
  private readonly store = new Map<string, CacheEntry<unknown>>();
  private maxEntries: number;
  private cleanupIntervalMs: number;
  private cleanupTimer: NodeJS.Timeout | null = null;

  constructor(config: Partial<CacheConfig> = {}) {
    this.maxEntries = toPositiveInt(
      config.maxEntries ?? DEFAULT_CACHE_MAX_ENTRIES,
      DEFAULT_CACHE_MAX_ENTRIES,
    );
    this.cleanupIntervalMs = toPositiveInt(
      config.cleanupIntervalMs ?? DEFAULT_CACHE_CLEANUP_INTERVAL_MS,
      DEFAULT_CACHE_CLEANUP_INTERVAL_MS,
    );
    this.startCleanupLoop();
  }

  configure(config: Partial<CacheConfig>): void {
    if (typeof config.maxEntries === 'number') {
      this.maxEntries = toPositiveInt(config.maxEntries, DEFAULT_CACHE_MAX_ENTRIES);
      this.evictIfNeeded();
    }

    if (typeof config.cleanupIntervalMs === 'number') {
      this.cleanupIntervalMs = toPositiveInt(
        config.cleanupIntervalMs,
        DEFAULT_CACHE_CLEANUP_INTERVAL_MS,
      );
      this.startCleanupLoop();
    }
  }

  get<T>(key: string): T | null {
    const cacheKey = hashCacheKey(key);
    const entry = this.store.get(cacheKey);
    if (!entry) {
      return null;
    }

    if (Date.now() > entry.expiresAt) {
      this.store.delete(cacheKey);
      return null;
    }

    // Keep most recently used entries at the end of the map.
    this.store.delete(cacheKey);
    this.store.set(cacheKey, entry);
    return entry.value as T;
  }

  set<T>(key: string, value: T, ttlMs: number): void {
    const cacheKey = hashCacheKey(key);
    this.store.delete(cacheKey);
    this.store.set(cacheKey, {
      value,
      expiresAt: Date.now() + ttlMs,
    });
    this.evictIfNeeded();
  }

  sweepExpiredEntries(now = Date.now()): void {
    for (const [key, entry] of this.store.entries()) {
      if (now > entry.expiresAt) {
        this.store.delete(key);
      }
    }
  }

  clear(): void {
    this.store.clear();
  }

  resetForTests(): void {
    this.clear();
    this.configure({
      maxEntries: DEFAULT_CACHE_MAX_ENTRIES,
      cleanupIntervalMs: DEFAULT_CACHE_CLEANUP_INTERVAL_MS,
    });
    this.startCleanupLoop();
  }

  private evictIfNeeded(): void {
    while (this.store.size > this.maxEntries) {
      const firstKey = this.store.keys().next().value;
      if (!firstKey) {
        return;
      }

      this.store.delete(firstKey);
    }
  }

  private startCleanupLoop(): void {
    if (this.cleanupTimer) {
      clearInterval(this.cleanupTimer);
      this.cleanupTimer = null;
    }

    this.cleanupTimer = setInterval(() => {
      this.sweepExpiredEntries();
    }, this.cleanupIntervalMs);
    this.cleanupTimer.unref?.();
  }
}

const memoryCache = new MemoryCache();
const inFlight = new Map<string, Promise<unknown>>();

let cacheBackend: CacheBackend = DEFAULT_CACHE_BACKEND;
let redisUrl: string | null = null;
let redisPrefix = DEFAULT_REDIS_PREFIX;
let redisClient: IORedis | null = null;
let redisReady = false;
let hasLoggedRedisFallback = false;

function logRedisFallback(error?: unknown): void {
  if (hasLoggedRedisFallback) {
    return;
  }

  hasLoggedRedisFallback = true;
  if (error) {
    console.warn('[bff][cache] Redis unavailable, falling back to in-memory cache.', error);
    return;
  }

  console.warn('[bff][cache] Redis unavailable, falling back to in-memory cache.');
}

function buildRedisCacheKey(rawKey: string): string {
  return `${redisPrefix}${hashCacheKey(rawKey)}`;
}

function teardownRedisClient(): void {
  if (redisClient) {
    redisClient.removeAllListeners();
    redisClient.disconnect();
  }

  redisClient = null;
  redisReady = false;
}

function ensureRedisClient(): void {
  if (cacheBackend !== 'redis' || !redisUrl || redisClient) {
    if (cacheBackend === 'redis' && !redisUrl) {
      logRedisFallback();
    }
    return;
  }

  try {
    const client = new IORedis(redisUrl, {
      maxRetriesPerRequest: 1,
      enableOfflineQueue: false,
    });

    client.on('ready', () => {
      redisReady = true;
      hasLoggedRedisFallback = false;
    });
    client.on('error', (error: unknown) => {
      redisReady = false;
      logRedisFallback(error);
    });
    client.on('end', () => {
      redisReady = false;
    });

    redisClient = client;
  } catch (error) {
    redisReady = false;
    logRedisFallback(error);
    redisClient = null;
  }
}

async function getFromRedis<T>(key: string): Promise<T | null> {
  if (!redisClient || !redisReady) {
    return null;
  }

  try {
    const payload = await redisClient.get(buildRedisCacheKey(key));
    if (!payload) {
      return null;
    }

    return JSON.parse(payload) as T;
  } catch (error) {
    redisReady = false;
    logRedisFallback(error);
    return null;
  }
}

async function setToRedis<T>(key: string, value: T, ttlMs: number): Promise<void> {
  if (!redisClient || !redisReady) {
    return;
  }

  try {
    await redisClient.set(
      buildRedisCacheKey(key),
      JSON.stringify(value),
      'PX',
      Math.max(1, Math.floor(ttlMs)),
    );
  } catch (error) {
    redisReady = false;
    logRedisFallback(error);
  }
}

async function getCachedValue<T>(key: string): Promise<T | null> {
  if (cacheBackend === 'redis') {
    const redisValue = await getFromRedis<T>(key);
    if (redisValue !== null) {
      return redisValue;
    }
  }

  return memoryCache.get<T>(key);
}

async function setCachedValue<T>(key: string, value: T, ttlMs: number): Promise<void> {
  memoryCache.set(key, value, ttlMs);

  if (cacheBackend === 'redis') {
    await setToRedis(key, value, ttlMs);
  }
}

function getInFlight<T>(key: string): Promise<T> | null {
  const pending = inFlight.get(hashCacheKey(key));
  return pending ? (pending as Promise<T>) : null;
}

function setInFlight<T>(key: string, promise: Promise<T>): void {
  inFlight.set(hashCacheKey(key), promise);
}

function clearInFlight(key: string): void {
  inFlight.delete(hashCacheKey(key));
}

export function configureCache(config: Partial<CacheConfig>): void {
  memoryCache.configure(config);

  const nextBackend =
    typeof config.backend === 'string'
      ? normalizeBackend(config.backend)
      : cacheBackend;
  const nextRedisUrl =
    typeof config.redisUrl === 'string'
      ? config.redisUrl.trim() || null
      : config.redisUrl === null
        ? null
        : redisUrl;
  const nextRedisPrefix =
    typeof config.redisPrefix === 'string'
      ? normalizeRedisPrefix(config.redisPrefix)
      : redisPrefix;

  const shouldReconnectRedis =
    nextBackend !== cacheBackend ||
    nextRedisUrl !== redisUrl ||
    nextRedisPrefix !== redisPrefix;

  cacheBackend = nextBackend;
  redisUrl = nextRedisUrl;
  redisPrefix = nextRedisPrefix;

  if (shouldReconnectRedis) {
    teardownRedisClient();
    hasLoggedRedisFallback = false;
  }

  ensureRedisClient();
}

export async function withCache<T>(
  key: string,
  ttlMs: number,
  producer: () => Promise<T>,
): Promise<T> {
  const cached = await getCachedValue<T>(key);
  if (cached !== null) {
    return cached;
  }

  const existingPromise = getInFlight<T>(key);
  if (existingPromise) {
    return existingPromise;
  }

  const pendingPromise = producer()
    .then(async value => {
      await setCachedValue(key, value, ttlMs);
      return value;
    })
    .finally(() => {
      clearInFlight(key);
    });

  setInFlight(key, pendingPromise);
  return pendingPromise;
}

export function resetCacheForTests(): void {
  memoryCache.resetForTests();
  inFlight.clear();
  cacheBackend = DEFAULT_CACHE_BACKEND;
  redisUrl = null;
  redisPrefix = DEFAULT_REDIS_PREFIX;
  hasLoggedRedisFallback = false;
  teardownRedisClient();
}
